const dateString = $json.date || "";
const date = new Date(dateString + "T12:00:00");
const dayOfWeek = date.getDay(); // 0=Dom, 1=Lun, 2=Mar, 3=Mié, 4=Jue, 5=Vie, 6=Sáb

// 1. SEGURIDAD: CONTROL DE FECHA INVÁLIDA
if (isNaN(dayOfWeek)) {
  return [{
    json: {
      status: "closed",
      message: "Ha habido un problema entendiendo la fecha de tu cita. ¿Podrías indicarme el día de nuevo?"
    }
  }];
}

// 2. FINES DE SEMANA (CERRADO PARA TODOS)
if (dayOfWeek === 0 || dayOfWeek === 6) {
  return [{
    json: {
      status: "closed",
      message: "La clínica está cerrada los fines de semana. Atendemos de lunes a viernes. ¿Qué día te viene bien?"
    }
  }];
}

// 3. NORMALIZAR SERVICIO Y TIEMPOS (A prueba de fallos)
const servicio = ($json.servicio || "").toString().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();

// Atrapamos "plexr" y errores tipográficos comunes
const esPlexr = servicio.includes("plexr") || servicio.includes("plexer");
const duracionMin = esPlexr ? 60 : 30;

const fromTimeStr = $json.fromTime || "00:00";
const [fh, fm] = fromTimeStr.split(":").map(Number);
const fromTotal = (fh || 0) * 60 + (fm || 0);
const toTotal = fromTotal + duracionMin;

const toHH = String(Math.floor(toTotal / 60)).padStart(2, "0");
const toMM = String(toTotal % 60).padStart(2, "0");
const toTime = `${toHH}:${toMM}:00`;


// 4. RUTAS ESTRICTAS POR TIPO DE SERVICIO

// --- RUTA A: PLEXR ---
if (esPlexr) {
  if (dayOfWeek !== 2 && dayOfWeek !== 4) {
    return [{
      json: {
        status: "closed",
        message: "El Plexr solo puede realizarse los martes o jueves de 17:00 a 20:00, ya que requiere la presencia de la Dra. Rosa. ¿Te viene bien alguno de esos días?"
      }
    }];
  }
  // 1020 = 17:00 hrs | 1200 = 20:00 hrs (Si es a las 19:00, cambia 1200 por 1140)
  if (fromTotal < 1020 || toTotal > 1200) {
    return [{
      json: {
        status: "closed",
        message: "El Plexr requiere la presencia de la Dra. Rosa, que solo está disponible de 17:00 a 20:00 los martes y jueves. La sesión es de 60 min y debe finalizar antes de las 20:00. ¿Te viene bien en ese horario?"
      }
    }];
  }
  // Si todo es correcto, aprueba y TERMINA
  return [{ json: { status: "open", categoria: "plexr", date: $json.date, fromTime: fromTimeStr, toTime: toTime } }];
}

// --- RUTA B: DRA. ROSA ---
const keywordsDraRosa = [
  "botox", "neuromodulador", "mesoneuromodulador", "bruxismo",
  "hilos tensores", "hilos", "relleno", "labio", "nariz", "ojera",
  "pomulo", "retensando", "fenol", "skin booster", "inductor",
  "colageno", "esclerosis", "varice", "microespuma", "mesoterapia",
  "exosoma", "polinucleotido", "valoracion", "intralipoterapia",
  "plasma rico", "prp"
];
const esDraRosa = keywordsDraRosa.some(k => servicio.includes(k));

if (esDraRosa) {
  if (dayOfWeek !== 2 && dayOfWeek !== 4) {
    return [{
      json: {
        status: "closed",
        message: "Los tratamientos médicos de la Dra. Rosa solo están disponibles los martes y jueves de 17:00 a 20:00. ¿Te viene bien alguno de esos días?"
      }
    }];
  }
  if (fromTotal < 1020 || toTotal > 1200) {
    return [{
      json: {
        status: "closed",
        message: "La Dra. Rosa atiende de 17:00 a 20:00 los martes y jueves. ¿Prefieres en ese horario?"
      }
    }];
  }
  return [{ json: { status: "open", categoria: "dra_rosa", date: $json.date, fromTime: fromTimeStr, toTime: toTime } }];
}

// --- RUTA C: HORARIO GENERAL (Maderoterapia y Resto) ---

// Validamos el horario general SOLO si no es Plexr ni Dra Rosa
if (dayOfWeek === 1 || dayOfWeek === 3 || dayOfWeek === 5) {
  if (fromTotal < 960 || toTotal > 1200) { // 16:00 a 20:00
    return [{
      json: {
        status: "closed",
        message: "Los lunes, miércoles y viernes atendemos de 16:00 a 20:00. ¿Prefieres en ese horario o cualquier día de martes a jueves de 12:00 a 20:00?"
      }
    }];
  }
} else if (dayOfWeek === 2 || dayOfWeek === 4) {
  if (fromTotal < 720 || toTotal > 1200) { // 12:00 a 20:00
    return [{
      json: {
        status: "closed",
        message: "Los martes y jueves atendemos de 12:00 a 20:00. ¿Prefieres en ese horario?"
      }
    }];
  }
}

// Si es maderoterapia facial
if (servicio.includes("maderoterapia facial")) {
  return [{ json: { status: "open", categoria: "rosi_only", date: $json.date, fromTime: fromTimeStr, toTime: toTime } }];
}

// Resto de tratamientos
return [{ json: { status: "open", categoria: "rosi_noa", date: $json.date, fromTime: fromTimeStr, toTime: toTime } }];

const items = $input.all();
const categoria = $('Clasificar y Validar').item.json.categoria;

// Extraer qué profesionales están ocupados en los eventos del calendario
const profesionalesOcupados = items
  .filter(item => item.json.start)
  .map(item => {
    const desc = item.json.description || item.json.summary || "";
    const match = desc.match(/PROFESIONAL:\s*(.+)/i);
    return match ? match[1].trim() : "desconocido";
  });

const rosiOcupada = profesionalesOcupados.some(p => p.toLowerCase().includes("rosi"));
const noaOcupada = profesionalesOcupados.some(p => p.toLowerCase().includes("noa"));
const draRosaOcupada = profesionalesOcupados.some(p =>
  p.toLowerCase().includes("dra. rosa") || p.toLowerCase().includes("dra rosa")
);

// --- DRA. ROSA ---
if (categoria === "dra_rosa") {
  if (draRosaOcupada) {
    return [{
      json: {
        status: "busy",
        message: "La Dra. Rosa ya tiene una cita en ese horario. ¿Te viene bien otro día o una hora diferente?"
      }
    }];
  }
  return [{
    json: {
      status: "free",
      profesional_asignada: "Dra. Rosa",
      message: "Horario disponible. Profesional asignada: Dra. Rosa."
    }
  }];
}

// --- ROSI ONLY (Maderoterapia Facial) ---
if (categoria === "rosi_only") {
  if (rosiOcupada) {
    return [{
      json: {
        status: "busy",
        message: "Rosi ya tiene una cita en ese horario. ¿Te viene bien otra hora?"
      }
    }];
  }
  return [{
    json: {
      status: "free",
      profesional_asignada: "Rosi",
      message: "Horario disponible. Profesional asignada: Rosi."
    }
  }];
}

// --- ROSI O NOA ---
if (categoria === "rosi_noa") {
  if (!rosiOcupada) {
    return [{
      json: {
        status: "free",
        profesional_asignada: "Rosi",
        message: "Horario disponible. Profesional asignada: Rosi."
      }
    }];
  }
  if (!noaOcupada) {
    return [{
      json: {
        status: "free",
        profesional_asignada: "Noa",
        message: "Horario disponible. Profesional asignada: Noa."
      }
    }];
  }
  return [{
    json: {
      status: "busy",
      message: "Tanto Rosi como Noa tienen citas en ese horario. ¿Prefieres otra hora?"
    }
  }];
}

// --- PLEXR ---
if (categoria === "plexr") {
  if (draRosaOcupada) {
    return [{
      json: {
        status: "busy",
        message: "La Dra. Rosa ya tiene una cita en ese horario y el Plexr requiere su presencia. ¿Te viene bien otro momento?"
      }
    }];
  }
  if (!rosiOcupada) {
    return [{
      json: {
        status: "free",
        profesional_asignada: "Rosi",
        message: "Horario disponible para Plexr. Profesional asignada: Rosi (con supervisión de Dra. Rosa)."
      }
    }];
  }
  if (!noaOcupada) {
    return [{
      json: {
        status: "free",
        profesional_asignada: "Noa",
        message: "Horario disponible para Plexr. Profesional asignada: Noa (con supervisión de Dra. Rosa)."
      }
    }];
  }
  return [{
    json: {
      status: "busy",
      message: "No hay disponibilidad para Plexr en ese horario. ¿Prefieres otro momento?"
    }
  }];
}

// Fallback
return [{
  json: {
    status: "free",
    profesional_asignada: "Rosi",
    message: "Horario disponible."
  }
}];

